class Solution {
public:
    int numMusicPlaylists(int n, int goal, int k) {
        const int MOD = 1e9 + 7;
        long long res = 1;
        for (int i = 1; i <= goal; i++) {
            res = res * (n - i + 1) * (i - k) % MOD;
        }
        return res;
    }
};
```
